"use client";

import { useState } from "react";

const API_BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

export default function QSignPage() {
  const [payloadText, setPayloadText] = useState('{ "hello": "AEVION" }');
  const [signature, setSignature] = useState("");
  const [verifySignature, setVerifySignature] = useState("");
  const [result, setResult] = useState<string>("");
  const [verifyingSigned, setVerifyingSigned] = useState(false);
  const [signedChecks, setSignedChecks] = useState<
    Array<{
      id: string;
      title: string;
      contentHash: string;
      valid: boolean;
    }>
  >([]);

  type SignedQRight = {
    id: string;
    title: string;
    contentHash: string;
    signature: string | null;
    createdAt: string;
  };

  const getAuthHeaders = () => {
    try {
      const t = localStorage.getItem("aevion_token") || "";
      return t ? { Authorization: `Bearer ${t}` } : undefined;
    } catch {
      return undefined;
    }
  };

  const sign = async () => {
    setResult("");
    try {
      const payload = JSON.parse(payloadText);

      const res = await fetch(`${API_BASE}/api/qsign/sign`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const data = await res.json().catch(() => null);
      if (!res.ok) {
        setResult(data?.error || "Ошибка подписи");
        return;
      }

      setSignature(data.signature || "");
      setResult(JSON.stringify(data, null, 2));
    } catch (e: any) {
      setResult("Ошибка JSON: " + e.message);
    }
  };

  const verify = async () => {
    setResult("");
    try {
      const payload = JSON.parse(payloadText);

      const res = await fetch(`${API_BASE}/api/qsign/verify`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          payload,
          signature: verifySignature || signature,
        }),
      });

      const data = await res.json().catch(() => null);
      if (!res.ok) {
        setResult(data?.error || "Ошибка проверки");
        return;
      }

      setResult(JSON.stringify(data, null, 2));
    } catch (e: any) {
      setResult("Ошибка JSON: " + e.message);
    }
  };

  const verifySignedQRight = async () => {
    setResult("");
    setVerifyingSigned(true);
    setSignedChecks([]);
    try {
      const headers = getAuthHeaders();

      const listRes = await fetch(`${API_BASE}/api/qright/objects/signed`, {
        headers,
      });
      const listData = await listRes.json().catch(() => null);
      if (!listRes.ok) {
        throw new Error(listData?.error || "Ошибка загрузки подписанных QRight");
      }

      const signed = (listData?.items || []) as SignedQRight[];
      const slice = signed.slice(0, 20);

      const results: Array<{
        id: string;
        title: string;
        contentHash: string;
        valid: boolean;
      }> = [];
      for (const it of slice) {
        if (!it.signature) continue;

        const res = await fetch(`${API_BASE}/api/qsign/verify`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            payload: { contentHash: it.contentHash },
            signature: it.signature,
          }),
        });

        const data = await res.json().catch(() => null);
        if (!res.ok) {
          results.push({ id: it.id, title: it.title, contentHash: it.contentHash, valid: false });
          continue;
        }
        results.push({
          id: it.id,
          title: it.title,
          contentHash: it.contentHash,
          valid: Boolean(data?.valid),
        });
      }

      setResult(
        JSON.stringify(
          {
            checked: results.length,
            results,
          },
          null,
          2
        )
      );
      setSignedChecks(results);
    } catch (e: any) {
      setResult(e?.message || "Ошибка проверки подписанных QRight");
    } finally {
      setVerifyingSigned(false);
    }
  };

  return (
    <main style={{ padding: 24, maxWidth: 900 }}>
      <h1 style={{ fontSize: 26 }}>QSign</h1>
      <p style={{ color: "#666" }}>Подпись и проверка целостности (MVP).</p>

      <div style={{ marginTop: 16 }}>
        <div style={{ fontWeight: 600, marginBottom: 6 }}>Payload (JSON)</div>
        <textarea
          value={payloadText}
          onChange={(e) => setPayloadText(e.target.value)}
          rows={8}
          style={{
            width: "100%",
            padding: 10,
            borderRadius: 8,
            border: "1px solid #ccc",
            fontFamily: "monospace",
          }}
        />
      </div>

      <div style={{ marginTop: 12, display: "flex", gap: 10 }}>
        <button onClick={sign}>Подписать</button>
        <button onClick={verify}>Проверить</button>
      </div>

      <section style={{ marginTop: 18, borderTop: "1px solid #eee", paddingTop: 16 }}>
        <div style={{ fontWeight: 600, marginBottom: 8 }}>
          QRight: проверка подписи из реестра
        </div>
        <div style={{ color: "#666", fontSize: 13, marginBottom: 10 }}>
          Берём `Подписанные` из QRight и проверяем HMAC (payload: `{"{contentHash}"}`).
        </div>
        <button
          type="button"
          onClick={verifySignedQRight}
          disabled={verifyingSigned}
          style={{
            padding: 10,
            borderRadius: 8,
            border: "1px solid #0a5",
            background: "#0a5",
            color: "#fff",
          }}
        >
          {verifyingSigned ? "Проверяем..." : "Проверить подписи QRight"}
        </button>

        {signedChecks.length > 0 && (
          <div
            style={{
              marginTop: 14,
              display: "grid",
              gap: 10,
            }}
          >
            {signedChecks.map((c) => (
              <div
                key={c.id}
                style={{
                  border: "1px solid #ddd",
                  borderRadius: 10,
                  padding: 12,
                  background: c.valid ? "#f4fff7" : "#fff5f5",
                }}
              >
                <div style={{ display: "flex", justifyContent: "space-between", gap: 10 }}>
                  <div style={{ fontWeight: 800 }}>{c.title}</div>
                  <div style={{ color: c.valid ? "#0a5" : "crimson", fontWeight: 800 }}>
                    {c.valid ? "валидна" : "невалидна"}
                  </div>
                </div>
                <div style={{ marginTop: 6, color: "#666", fontSize: 12 }}>
                  contentHash:{" "}
                  <span style={{ fontFamily: "monospace" }}>
                    {c.contentHash.slice(0, 10)}…{c.contentHash.slice(-6)}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      <div style={{ marginTop: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 6 }}>Подпись</div>
        <input
          value={signature}
          readOnly
          style={{
            width: "100%",
            padding: 8,
            borderRadius: 8,
            border: "1px solid #ccc",
            fontSize: 12,
          }}
        />
      </div>

      <div style={{ marginTop: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 6 }}>
          Подпись для проверки (опционально)
        </div>
        <input
          value={verifySignature}
          onChange={(e) => setVerifySignature(e.target.value)}
          placeholder="Если пусто — проверим подпись выше"
          style={{
            width: "100%",
            padding: 8,
            borderRadius: 8,
            border: "1px solid #ccc",
            fontSize: 12,
          }}
        />
      </div>

      <div style={{ marginTop: 16 }}>
        <div style={{ fontWeight: 600, marginBottom: 6 }}>Результат</div>
        <pre
          style={{
            background: "#f5f5f5",
            padding: 12,
            borderRadius: 8,
            fontSize: 12,
            whiteSpace: "pre-wrap",
          }}
        >
          {result || "—"}
        </pre>
      </div>
    </main>
  );
}
